body);\n  cursor: pointer;\n  transition: all 0.2s;\n  color: var(--text-soft);\n}\n.admin-tab__icon[_ngcontent-%COMP%] {\n  font-size: 1.2rem;\n}\n.admin-tab__label[_ngcontent-%COMP%] {\n  font-size: 0.68rem;\n  font-weight: 500;\n  letter-spacing: 0.06em;\n}\n.admin-tab.active[_ngcontent-%COMP%] {\n  background: linear-gradient(135deg, var(--serenity-pale), var(--lilac-pale));\n  color: var(--serenity-dark);\n}\n.admin-tab[_ngcontent-%COMP%]:hover:not(.active) {\n  background: var(--serenity-pale);\n  color: var(--text-mid);\n}\n@media (max-width: 600px) {\n  .admin-tab[_ngcontent-%COMP%] {\n    min-width: 55px;\n  }\n  .admin-tab__label[_ngcontent-%COMP%] {\n    font-size: 0.58rem;\n  }\n}\n\n.stats-grid[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(170px, 1fr));\n  gap: 1.2rem;\n  margin-bottom: 2rem;\n}\n\n.stat-card[_ngcontent-%COMP%] {\n  background: white;\n  border-radius: var(--radius-lg);\n  padding: 1.5rem 1.2rem;\n  text-align: center;\n  box-shadow: var(--shadow-sm);\n  border: 1px solid rgba(146, 168, 209, 0.12);\n  transition: transform 0.2s;\n}\n.stat-card[_ngcontent-%COMP%]:hover {\n  transform: translateY(-3px);\n}\n.stat-card__icon[_ngcontent-%COMP%] {\n  font-size: 1.8rem;\n  display: block;\n  margin-bottom: 0.5rem;\n}\n.stat-card__value[_ngcontent-%COMP%] {\n  font-family: var(--font-serif);\n  font-size: 1.9rem;\n  font-style: italic;\n  display: block;\n  line-height: 1.1;\n  margin-bottom: 0.3rem;\n}\n.stat-card__label[_ngcontent-%COMP%] {\n  font-size: 0.68rem;\n  letter-spacing: 0.15em;\n  text-transform: uppercase;\n  color: var(--text-soft);\n}\n.stat-card--blue[_ngcontent-%COMP%]   .stat-card__value[_ngcontent-%COMP%] {\n  color: var(--serenity-dark);\n}\n.stat-card--lilac[_ngcontent-%COMP%]   .stat-card__value[_ngcontent-%COMP%] {\n  color: var(--lilac-dark);\n}\n.stat-card--gold[_ngcontent-%COMP%]   .stat-card__value[_ngcontent-%COMP%] {\n  color: var(--gold);\n}\n.stat-card--green[_ngconte