\n  flex-direction: column;\n  gap: 0.1rem;\n}\n.message-card__header[_ngcontent-%COMP%]   strong[_ngcontent-%COMP%] {\n  font-size: 0.92rem;\n  color: var(--text-dark);\n}\n.message-card__header[_ngcontent-%COMP%]   small[_ngcontent-%COMP%] {\n  font-size: 0.75rem;\n  color: var(--text-soft);\n}\n.message-card__date[_ngcontent-%COMP%] {\n  font-size: 0.75rem;\n  color: var(--text-soft);\n  flex-shrink: 0;\n}\n.message-card__text[_ngcontent-%COMP%] {\n  font-family: var(--font-serif);\n  font-size: 1.05rem;\n  font-style: italic;\n  color: var(--text-mid);\n  line-height: 1.7;\n  border: none;\n  padding: 0;\n  margin: 0 0 0.7rem;\n}\n.message-card__itens[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 0.5rem;\n  flex-wrap: wrap;\n  font-size: 0.78rem;\n  color: var(--text-soft);\n}\n\n.empty-card[_ngcontent-%COMP%] {\n  text-align: center;\n  padding: 3rem 2rem;\n  color: var(--text-soft);\n}\n.empty-card[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  font-size: 3rem;\n  display: block;\n  margin-bottom: 1rem;\n  opacity: 0.5;\n}\n.empty-card[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  font-family: var(--font-serif);\n  font-size: 1.1rem;\n  font-style: italic;\n}\n\n.item-emoji[_ngcontent-%COMP%] {\n  font-size: 1.3rem;\n  cursor: default;\n}\n\n.empty-row[_ngcontent-%COMP%] {\n  text-align: center;\n  color: var(--text-soft);\n  font-style: italic;\n  padding: 1.5rem !important;\n}\n\n.empty-row-inline[_ngcontent-%COMP%] {\n  padding: 1.5rem;\n  text-align: center;\n  color: var(--text-soft);\n  font-style: italic;\n  font-size: 0.9rem;\n}\n\n.btn-icon[_ngcontent-%COMP%] {\n  background: none;\n  border: none;\n  cursor: pointer;\n  padding: 0.3rem 0.5rem;\n  border-radius: 6px;\n  font-size: 0.9rem;\n  transition: all 0.2s;\n}\n.btn-icon--danger[_ngcontent-%COMP%] {\n  color: var(--text-soft);\n}\n.btn-icon--danger[_ngcontent-%COMP%]:hover {\n  color: #e74c3c;\n  background: #fdecea;\n}\n\n.btn--sm[_ngcontent-%COMP%] {\n  padding: 0.55rem 1.2rem;\n  font-si