import { Component, inject, OnInit } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { DatePipe, NgClass, NgFor, NgIf } from '@angular/common';
import { BrlPipe } from '../../shared/pipes/brl.pipe';
import { ToastService } from 'src/app/shared/components/toast/toast.service';
import { rsvpService } from '../rsvp/rsvp.service';
import { AuthService } from './Auth.service';
import { AdminLoginRequest } from './admin.model';
import { GiftService } from '../gifts/gift.service';
import { PaymentService } from '../payment/Payment.service';
import {  FormaPagamento, StatusPagamento, PaymentResponse } from '../payment/Payment.model';
import { Gift, GiftForm } from '../gifts/gift.model';
import { RsvpResponse } from '../rsvp/rsvp.model';

type AdminTab = 'dashboard' | 'catalogo' | 'presentes' | 'presencas' | 'mensagens' | 'convites';

@Component({
  selector: 'app-admin',
  standalone: true,
  imports: [FormsModule, NgClass, BrlPipe, NgIf, NgFor, DatePipe],
  templateUrl: './admin.component.html',
  styleUrls: ['./admin.component.scss'],
})
export class AdminComponent implements OnInit {
   auth         = inject(AuthService);
   presenteSvc  = inject(GiftService);
   pagamentoSvc = inject(PaymentService);
   conviteSvc   = inject(rsvpService);
   toastSvc     = inject(ToastService);

  // Expõe auth para o template (*ngIf="auth.isLoggedIn()")
  readonly authRef = this.auth;

  // ── Auth ──────────────────────────────────
  loginUser = '';
  loginPass = '';
  loginErr  = '';
  logging   = false;

  // ── Tab ───────────────────────────────────
  activeTab: AdminTab = 'dashboard';

  // ── Catálogo ──────────────────────────────
  catalogo: Gift[]  = [];
  showGiftForm      = false;
  giftForm: GiftForm & { imagemUrl: string } = {
    nome: '', descricao: '', valor: 0, imagemUrl: '',
  };

  // ── Presentes recebidos ───────────────────
  presentesRecebidos: PaymentResponse[] = [];

  // ── Convites ──────────────────────────────
  convites: RsvpResponse[] = [];
  showConviteForm = false;
  conviteForm     = { codigo: '', familia: '', convidadosStr: '' };

  // ── Getters derivados (equivalente a computed) ────────────────────────────

  get ultimosPresentes(): PaymentResponse[] {
    return [...this.presentesRecebidos]
      .sort((a, b) =>
        new Date(b.criadoEm ?? 0).getTime() -
        new Date(a.criadoEm ?? 0).getTime()
      )
      .slice(0, 5);
  }
  /** Soma somente pagamentos com status PAGO */
  get totalArrecadado(): number {
    return this.presentesRecebidos
      .filter(p => p.statusPagamento === 'PAGO')
      .reduce((acc, p) => acc + p.total, 0);
  }

  get mensagens(): PaymentResponse[] {
    return this.presentesRecebidos.filter(p => p.mensagem?.trim());
  }

  get confirmados(): number {
    return this._contar('CONFIRMADO');
  }

  get talvez(): number {
    return this._contar('TALVEZ');
  }

  get naoVem(): number {
    return this._contar('NAO_VEM');
  }

  get pendentes(): number {
    return this._contar('PENDENTE');
  }

  private _contar(status: string): number {
    return this.convites.flatMap(c => c.convidados).filter(g => g.status === status).length;
  }

  // ── Lifecycle ─────────────────────────────
  ngOnInit(): void {
    if (this.auth.isLoggedIn()) this.loadData();
  }

  // ── Auth ──────────────────────────────────
  login(): void {
    const req: AdminLoginRequest = { username: this.loginUser, password: this.loginPass };
    this.logging = true;
    this.loginErr = '';
    this.auth.login(req).subscribe({
      next: () => { this.logging = false; this.loadData(); },
      error: () => { this.logging = false; this.loginErr = 'Usuário ou senha incorretos.'; },
    });
  }

  logout(): void { this.auth.logout(); }

  // ── Data ──────────────────────────────────
  loadData(): void {
    this.presenteSvc.listar().subscribe(p  => this.catalogo           = p);
    this.pagamentoSvc.listar().subscribe(c => this.presentesRecebidos = c);
    this.conviteSvc.listar().subscribe(c => this.convites        = c);
  }

  setTab(tab: AdminTab): void { this.activeTab = tab; }

  // ── Catálogo CRUD ─────────────────────────
  addPresente(): void {
    const f = this.giftForm;
    if (!f.nome.trim() || !f.valor) {
      this.toastSvc.error('Preencha nome e valor!');
      return;
    }
    this.presenteSvc.criar(f).subscribe(p => {
      this.catalogo = [...this.catalogo, p];
      this.showGiftForm = false;
      this.giftForm = { nome: '', descricao: '', valor: 0, imagemUrl: '' };
      this.toastSvc.success(`"${p.nome}" adicionado! 🎁`);
    });
  }

  removePresente(id: number): void {
    if (!confirm('Remover este presente?')) return;
    this.presenteSvc.deletar(id).subscribe(() => {
      this.catalogo = this.catalogo.filter(p => p.id !== id);
      this.toastSvc.success('Presente removido.');
    });
  }

  // ── Convites CRUD ─────────────────────────
  addConvite(): void {
    const f = this.conviteForm;
    if (!f.codigo.trim() || !f.familia.trim()) {
      this.toastSvc.error('Preencha código e família!');
      return;
    }
    const convidados = f.convidadosStr
      .split('\n')
      .map(s => s.trim())
      .filter(s => s.length > 0);
    if (!convidados.length) {
      this.toastSvc.error('Adicione pelo menos um convidado!');
      return;
    }
    this.conviteSvc.criar({ codigo: f.codigo, familia: f.familia, convidados }).subscribe(c => {
      this.convites = [...this.convites, c];
      this.showConviteForm = false;
      this.conviteForm = { codigo: '', familia: '', convidadosStr: '' };
      this.toastSvc.success(`Convite ${c.codigo} criado! 🎟️`);
    });
  }

  removeConvite(id: number): void {
    if (!confirm('Remover este convite?')) return;
    this.conviteSvc.deletar(id).subscribe(() => {
      this.convites = this.convites.filter(c => c.id !== id);
      this.toastSvc.success('Convite removido.');
    });
  }

  // ── Helpers de label ──────────────────────

  pagamentoLabel(forma: FormaPagamento): string {
    const map: Record<FormaPagamento, string> = {
      PIX:    'Pix 🔑',
      CARTAO: 'Cartão 💳',
    };
    return map[forma] ?? forma;
  }

  statusPagLabel(status: StatusPagamento['status']): string {
    const map: Record<StatusPagamento['status'], string> = {
      PAGO: '✓ Pago',
      PENDENTE: '⏳ Pendente',
      EXPIRADO: '✗ Expirado',
    };

    return map[status] ?? status;
  }

  statusClass(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: 'badge--confirm',
      TALVEZ:     'badge--maybe',
      NAO_VEM:    'badge--decline',
      PENDENTE:   'badge--pending',
    };
    return map[status] ?? '';
  }

  statusLabel(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: '✓ Confirmado',
      TALVEZ:     '? Talvez',
      NAO_VEM:    '✗ Não vem',
      PENDENTE:   '⏳ Pendente',
    };
    return map[status] ?? status;
  }

  confirmadosCount(convite: RsvpResponse): number {
    return convite.convidados.filter(g => g.status === 'CONFIRMADO').length;
  }

  trackById(_i: number, item: { id: number }): number {
    return item.id;
  }
}
